    39→}
    40→
    41→func newScIdentityCache(ids identity.IdentityMap) scIdentityCache {
    42→	idCache := scIdentityCache{
    43→		ids:         make(map[identity.NumericIdentity]*scIdentity, len(ids)),
    44→		byNamespace: make(map[string]map[*scIdentity]struct{}, len(ids)),
    45→	}
    46→
