package policy

import (
	"bytes"
	"context"
	"errors"
	"log/slog"
	"strings"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
)

func TestNewPolicyAuditLogger(t *testing.T) {
	buffer := &bytes.Buffer{}
	logger := slog.New(slog.NewTextHandler(buffer, &slog.HandlerOptions{Level: slog.LevelInfo}))

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo, buffer)
	require.NotNil(t, pal)
	assert.Equal(t, slog.LevelInfo, pal.GetLevel())
}

func TestNewPolicyAuditLoggerWithNilLogger(t *testing.T) {
	buffer := &bytes.Buffer{}

	pal := NewPolicyAuditLogger(nil, slog.LevelInfo, buffer)
	require.NotNil(t, pal)
	assert.NotNil(t, pal.logger)
	assert.Equal(t, slog.LevelInfo, pal.GetLevel())
}

func TestLogDecision(t *testing.T) {
	buffer := &bytes.Buffer{}
	logger := slog.New(slog.NewTextHandler(buffer, &slog.HandlerOptions{Level: slog.LevelInfo}))

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo, buffer)

	testIdentity := identity.NumericIdentity(1000)
	testPolicy := "ingress"
	testVerdict := "allowed"
	testReason := "policy matches"

	pal.LogDecision(testIdentity, testPolicy, testVerdict, testReason)

	output := buffer.String()
	assert.Contains(t, output, "policy decision")
	assert.Contains(t, output, "1000")
	assert.Contains(t, output, "ingress")
	assert.Contains(t, output, "allowed")
	assert.Contains(t, output, "policy matches")
}

func TestLogDecisionWithNilLogger(t *testing.T) {
	// This should not panic
	pal := &PolicyAuditLogger{
		logger: nil,
		level:  slog.LevelInfo,
	}

	testIdentity := identity.NumericIdentity(1000)
	pal.LogDecision(testIdentity, "policy", "allowed", "reason")
	// No error should occur
}

func TestLogEvaluation(t *testing.T) {
	buffer := &bytes.Buffer{}
	logger := slog.New(slog.NewTextHandler(buffer, &slog.HandlerOptions{Level: slog.LevelInfo}))

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo, buffer)

	result := &EvaluationResult{
		Allowed: true,
		Denied:  false,
		Error:   nil,
	}

	ctx := context.Background()
	pal.LogEvaluation(ctx, "test-policy", nil, result)

	output := buffer.String()
	assert.Contains(t, output, "policy evaluation")
	assert.Contains(t, output, "test-policy")
	assert.Contains(t, output, "allowed")
}

func TestLogEvaluationWithError(t *testing.T) {
	buffer := &bytes.Buffer{}
	logger := slog.New(slog.NewTextHandler(buffer, &slog.HandlerOptions{Level: slog.LevelInfo}))

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo, buffer)

	testErr := errors.New("policy evaluation error")
	result := &EvaluationResult{
		Allowed: false,
		Denied:  true,
		Error:   testErr,
	}

	ctx := context.Background()
	pal.LogEvaluation(ctx, "test-policy", nil, result)

	output := buffer.String()
	assert.Contains(t, output, "policy evaluation")
	assert.Contains(t, output, "test-policy")
	assert.Contains(t, output, "denied")
	assert.Contains(t, output, "policy evaluation error")
}

func TestLogEvaluationWithSelectorCache(t *testing.T) {
	buffer := &bytes.Buffer{}
	logger := slog.New(slog.NewTextHandler(buffer, &slog.HandlerOptions{Level: slog.LevelInfo}))

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo, buffer)

	// Create a mock SelectorCache with Len() method
	mockCache := &SelectorCache{
		idCache: newScIdentityCache(nil),
	}

	result := &EvaluationResult{
		Allowed: true,
		Denied:  false,
		Error:   nil,
	}

	ctx := context.Background()
	pal.LogEvaluation(ctx, "test-policy", mockCache, result)

	output := buffer.String()
	assert.Contains(t, output, "policy evaluation")
	assert.Contains(t, output, "cacheSize")
}

func TestSetLevel(t *testing.T) {
	buffer := &bytes.Buffer{}
	pal := NewPolicyAuditLogger(nil, slog.LevelInfo, buffer)

	assert.Equal(t, slog.LevelInfo, pal.GetLevel())

	pal.SetLevel(slog.LevelDebug)
	assert.Equal(t, slog.LevelDebug, pal.GetLevel())

	pal.SetLevel(slog.LevelError)
	assert.Equal(t, slog.LevelError, pal.GetLevel())
}

func TestThreadSafety(t *testing.T) {
	buffer := &bytes.Buffer{}
	logger := slog.New(slog.NewTextHandler(buffer, &slog.HandlerOptions{Level: slog.LevelInfo}))

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo, buffer)

	// Run multiple goroutines to test thread safety
	done := make(chan bool, 3)

	go func() {
		for i := 0; i < 10; i++ {
			pal.LogDecision(identity.NumericIdentity(i), "policy", "allowed", "test")
		}
		done <- true
	}()

	go func() {
		for i := 0; i < 10; i++ {
			result := &EvaluationResult{
				Allowed: true,
				Denied:  false,
				Error:   nil,
			}
			pal.LogEvaluation(context.Background(), "policy", nil, result)
		}
		done <- true
	}()

	go func() {
		for i := 0; i < 10; i++ {
			pal.SetLevel(slog.LevelInfo)
			_ = pal.GetLevel()
		}
		done <- true
	}()

	// Wait for all goroutines to complete
	for i := 0; i < 3; i++ {
		<-done
	}
}

func TestLogDecisionJSON(t *testing.T) {
	buffer := &bytes.Buffer{}
	handler := slog.NewJSONHandler(buffer, &slog.HandlerOptions{Level: slog.LevelInfo})
	logger := slog.New(handler)

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo, buffer)

	testIdentity := identity.NumericIdentity(2000)
	pal.LogDecision(testIdentity, "egress", "denied", "policy denies traffic")

	output := buffer.String()
	// Verify JSON output contains expected fields
	assert.Contains(t, output, "policy decision")
	assert.Contains(t, output, "2000")
	assert.Contains(t, output, "egress")
	assert.Contains(t, output, "denied")

	// Verify it's valid JSON by checking for JSON structure
	assert.True(t, strings.HasPrefix(strings.TrimSpace(output), "{"), "Output should be valid JSON")
}

func TestLogEvaluationNilLogger(t *testing.T) {
	// This should not panic
	pal := &PolicyAuditLogger{
		logger: nil,
		level:  slog.LevelInfo,
	}

	result := &EvaluationResult{
		Allowed: true,
		Denied:  false,
		Error:   nil,
	}

	ctx := context.Background()
	pal.LogEvaluation(ctx, "test-policy", nil, result)
	// No error should occur
}

