package policy

import (
	"context"
	"io"
	"log/slog"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging/logfields"
	"github.com/cilium/cilium/pkg/policy/types"
)

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes.
type PolicyAuditLogger struct {
	lock.Mutex

	logger *slog.Logger
	level  slog.Level
	output io.Writer
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the specified logger,
// log level, and output destination.
func NewPolicyAuditLogger(logger *slog.Logger, level slog.Level, output io.Writer) *PolicyAuditLogger {
	if logger == nil {
		logger = slog.New(slog.NewTextHandler(output, &slog.HandlerOptions{Level: level}))
	}
	return &PolicyAuditLogger{
		logger: logger,
		level:  level,
		output: output,
	}
}

// LogDecision logs a policy decision with the given identity, policy, verdict, and reason.
// This method is thread-safe.
func (pal *PolicyAuditLogger) LogDecision(identity identity.NumericIdentity, policy string, verdict string, reason string) {
	pal.Lock()
	defer pal.Unlock()

	if pal.logger == nil {
		return
	}

	pal.logger.Log(context.Background(), pal.level, "policy decision",
		logfields.Identity, identity,
		"policy", policy,
		"verdict", verdict,
		"reason", reason,
	)
}

// EvaluationResult represents the result of a policy evaluation.
type EvaluationResult struct {
	Allowed bool
	Denied  bool
	Error   error
}

// LogEvaluation logs a policy evaluation with the given context, policy key, selector cache, and result.
// This method is thread-safe.
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey string, selectorCache *SelectorCache, result *EvaluationResult) {
	pal.Lock()
	defer pal.Unlock()

	if pal.logger == nil {
		return
	}

	attrs := []any{
		"policyKey", policyKey,
		"allowed", result.Allowed,
		"denied", result.Denied,
	}

	if result.Error != nil {
		attrs = append(attrs, logfields.Error, result.Error)
	}

	if selectorCache != nil {
		attrs = append(attrs, "cacheSize", selectorCache.Len())
	}

	pal.logger.Log(ctx, pal.level, "policy evaluation",
		attrs...,
	)
}

// SetLevel sets the log level for the audit logger.
// This method is thread-safe.
func (pal *PolicyAuditLogger) SetLevel(level slog.Level) {
	pal.Lock()
	defer pal.Unlock()
	pal.level = level
}

// GetLevel returns the current log level.
// This method is thread-safe.
func (pal *PolicyAuditLogger) GetLevel() slog.Level {
	pal.Lock()
	defer pal.Unlock()
	return pal.level
}

