	// Run multiple goroutines to test thread safety
	done := make(chan bool, 3)

	go func() {
		for i := 0; i < 10; i++ {
			pal.LogDecision(identity.NumericIdentity(i), "policy", "allowed", "test")
		}
		done <- true
	}()

	go func() {
		for i := 0; i < 10; i++ {
			result := &EvaluationResult{
				Allowed: true,
				Denied:  false,
				Error:   nil,
			}
			pal.LogEvaluation(context.Background(), "policy", nil, result)
