	defer pal.Unlock()

	if pal.logger == nil {
		return
	}

	pal.logger.Log(context.Background(), pal.level, "policy decision",
		logfields.Identity, identity,
		"policy", policy,
		"verdict", verdict,
		"reason", reason,
	)
}

// EvaluationResult represents the result of a policy evaluation.
type EvaluationResult struct {
	Allowed bool
	Denied  bool
	Error   error
}

// LogEvaluation logs a policy evaluation with the given context, policy key, selector cache, and result.
// This method is thread-safe.
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey string, selectorCache *SelectorCache, result *EvaluationResult) {
	pal.Lock()
	defer pal.Unlock()

	if pal.logger == nil {
		return
	}

	attrs := []any{
		"policyKey", policyKey,
		"allowed", result.Allowed,
		"denied", result.Denied,
	}

	if result.Error != nil {
		attrs = append(attrs, logfields.Error, result.Error)
	}

	if selectorCache != nil {
		stats := selectorCache.Stats()
		attrs = append(attrs, "selectors", stats.selectors, "identities", stats.identities)
	}

	pal.logger.Log(ctx, pal.level, "policy evaluation",
		attrs...,
	)
}

// SetLevel sets the log level for the audit logger.
// This method is thread-safe.
func (pal *PolicyAuditLogger) SetLevel(level slog.Level) {
	pal.Lock()
	defer pal.Unlock()
	pal.level = level
}

// GetLevel returns the current log level.
// This method is thread-safe.
func (pal *PolicyAuditLogger) GetLevel() slog.Level {
	pal.Lock()
	defer pal.Unlock()
	return pal.level
}

